class Dog
{
public:
    string name;
    int age;
    void eat() { cout << name << " is eating."; }
};

class Cat
{
public:
    string name; // duplicated
    int age;     // duplicated
    void eat() { cout << name << " is eating."; } // duplicated
};

class Animal // base class
{
public:
    string name;

    void eat()
    {
        cout << name << " is eating." << endl;
    }
};

class Dog : public Animal // Dog derives from Animal
{
public:
    void bark()
    {
        cout << name << " says Woof!" << endl;
    }
};

#include <iostream>
#include <string>

using namespace std;

class Animal
{
public:
    string name;

    void eat()
    {
        cout << name << " is eating." << endl;
    }
};

class Dog : public Animal
{
public:
    void bark()
    {
        cout << name << " says Woof!" << endl;
    }
};

int main()
{
    Dog d;
    d.name = "Rex";

    d.eat();
    d.bark();

    return 0;
}

class Animal
{
protected:
    string name; // NOT public, but still reachable from Dog

public:
    void setName(string n)
    {
        name = n;
    }
};

class Dog : public Animal
{
public:
    void bark()
    {
        cout << name << " says Woof!"; // fine — protected is visible to derived classes
    }
};

#include <iostream>

using namespace std;

class Animal
{
public:
    Animal()
    {
        cout << "Animal constructed" << endl;
    }
};

class Dog : public Animal
{
public:
    Dog()
    {
        cout << "Dog constructed" << endl;
    }
};

int main()
{
    Dog d;

    return 0;
}

